 <UnheadProvider>
 <Head>
 <link rel="shortcut icon" href="/favicon.ico" />
 </Head>
 <Router>
 {/* Вот тут уже у нас есть контекст роутера, то есть тут можем вызывать хук useLocation() и прочие */}
